        @mcp.tool()
        async def cells_get_workbook_info(input_filename: str) -> dict:
            """
            Retrieve basic information about a workbook stored on the server.
        
            IMPORTANT:
            * All *_filename parameters accept ONLY the bare filename (e.g. 'report.xlsx') — no path, no directory, no drive letter, no slash.
            * The file MUST already exist in the server's ASPOSE_FILES_PATH folder before calling this tool.
            * Do NOT ask the user to upload a file — files are pre‑placed in the server folder by the user.
            * The output file is also written to the ASPOSE_FILES_PATH folder; the returned output_filename is the bare name only.
        
            Args:
                input_filename: Bare filename of the workbook to inspect, e.g. "report.xlsx". The file must already exist in ASPOSE_FILES_PATH.
        
            Returns:
                dict: A dictionary containing at minimum the keys:
                    - "status": "success" or "error"
                    - "message": Human‑readable description
                    - "sheet_count": Number of worksheets in the workbook
                    - "sheet_names": List of worksheet names
                    - "document_properties": Mapping of common built‑in document properties (title, author, etc.)
        
            Raises:
                FileNotFoundError: If the specified workbook file does not exist.
                Exception: Any unexpected error raised by Aspose.Cells.
        
            Example:
                >>> result = await cells_get_workbook_info("report.xlsx")
                >>> result["sheet_count"]
                3
            """
            # ----------------------------------------------------------------------
            # Validate and resolve the input filename
            # ----------------------------------------------------------------------
            from pathlib import Path
            from mcp_server.path_utils import get_safe_path
        
            # Sanitize the caller‑provided filename (strip null bytes, keep only the name)
            input_filename = Path(input_filename.strip().replace('\x00', '')).name
            resolved_input = get_safe_path(input_filename)
        
            if not Path(resolved_input).is_file():
                raise FileNotFoundError(f"File not found: {input_filename}")
        
            # ----------------------------------------------------------------------
            # Import Aspose lazily (after validation)
            # ----------------------------------------------------------------------
            import aspose.cells as ac
            import logging
        
            logger = logging.getLogger(__name__)
        
            try:
                # Load the workbook using the resolved absolute path
                wb = ac.Workbook(str(resolved_input))
        
                # Worksheet information
                sheet_count = len(wb.worksheets)
                sheet_names = [ws.name for ws in wb.worksheets]
        
                # Built‑in document properties (extract a few common ones safely)
                props = wb.built_in_document_properties
                document_properties = {
                    "title": getattr(props, "title", None),
                    "author": getattr(props, "author", None),
                    "subject": getattr(props, "subject", None),
                    "keywords": getattr(props, "keywords", None),
                    "comments": getattr(props, "comments", None),
                    "last_author": getattr(props, "last_author", None),
                    "created_time": getattr(props, "created_time", None).isoformat()
                    if getattr(props, "created_time", None) else None,
                    "last_saved_time": getattr(props, "last_saved_time", None).isoformat()
                    if getattr(props, "last_saved_time", None) else None,
                }
        
                logger.debug(
                    "Workbook %s loaded: %d sheets, properties %s",
                    input_filename,
                    sheet_count,
                    document_properties,
                )
        
                return {
                    "status": "success",
                    "message": "Workbook information retrieved successfully.",
                    "sheet_count": sheet_count,
                    "sheet_names": sheet_names,
                    "document_properties": document_properties,
                }
        
            except Exception as exc:  # pragma: no cover
                logger.exception("Error processing workbook %s", input_filename)
                return {"status": "error", "message": str(exc)}

        @mcp.tool()
        async def cells_read_cell_value(
            input_filename: str,
            sheet_index: int,
            cell_address: str
        ) -> dict:
            """
            Read a cell value from an Excel workbook stored on the server.
        
            IMPORTANT:
            * All *_filename parameters accept ONLY the bare filename (e.g. 'scan.jpg') — no path, no directory, no drive letter, no slash.
            * The file MUST already exist in the server's ASPOSE_FILES_PATH folder before calling this tool.
            * Do NOT ask the user to upload a file — files are pre‑placed in the server folder by the user.
            * The output file is also written to the ASPOSE_FILES_PATH folder; the returned output_filename is the bare name only.
        
            Args:
                input_filename (str): Workbook file to read from. Bare filename only, e.g. "report.xlsx".
                sheet_index (int): Zero‑based index of the worksheet.
                cell_address (str): Cell address in A1 notation (e.g., "B2").
        
            Returns:
                dict: {
                    "status": "success" | "error",
                    "message": str,
                    "value": str (present only on success)
                }
        
            Raises:
                FileNotFoundError: If the workbook file does not exist.
                IndexError: If sheet_index is out of range.
                ValueError: If cell_address is invalid.
                Exception: For any other unexpected errors.
        
            Example:
                result = await cells_read_cell_value(
                    input_filename="sales.xlsx",
                    sheet_index=0,
                    cell_address="C5"
                )
                # result => {"status":"success","message":"Cell value retrieved.","value":"12345"}
            """
            from pathlib import Path
            from mcp_server.path_utils import get_safe_path
            import logging
        
            # Sanitize and resolve the input workbook filename
            input_filename = Path(input_filename.strip().replace('\x00', '')).name
            resolved_input = get_safe_path(input_filename)
            if not Path(resolved_input).is_file():
                raise FileNotFoundError(f"File not found: {input_filename}")
        
            logger = logging.getLogger(__name__)
        
            try:
                import aspose.cells as ac
        
                # Load workbook
                wb = ac.Workbook(str(resolved_input))
        
                # Access worksheet by index
                try:
                    ws = wb.worksheets[sheet_index]
                except IndexError as ie:
                    raise IndexError(f"Worksheet index {sheet_index} is out of range.") from ie
        
                # Retrieve the cell
                try:
                    cell = ws.cells.get(cell_address)
                except Exception as e:
                    raise ValueError(f"Invalid cell address '{cell_address}'.") from e
        
                # Get string representation of the cell value
                value = cell.string_value
        
                return {
                    "status": "success",
                    "message": "Cell value retrieved.",
                    "value": value
                }
        
            except Exception as exc:
                logger.exception("Error reading cell value from workbook.")
                return {
                    "status": "error",
                    "message": str(exc)
                }

