        async def cells_set_cell_formula(
            input_filename: str,
            sheet_index: int,
            cell_address: str,
            formula: str,
            output_filename: str | None = None,
        ) -> dict:
            """
            Set a formula for a specific cell in an existing workbook.
        
            IMPORTANT:
            * All *_filename parameters accept ONLY the bare filename (e.g. 'scan.jpg') — no path, no directory, no drive letter, no slash.
            * The file MUST already exist in the server's ASPOSE_FILES_PATH folder before calling this tool.
            * Do NOT ask the user to upload a file — files are pre‑placed in the server folder by the user.
            * The output file is also written to the ASPOSE_FILES_PATH folder; the returned output_filename is the bare name only.
        
            Args:
                input_filename: Bare filename of the workbook to modify, e.g. "book.xlsx".
                sheet_index: Zero‑based index of the worksheet that contains the target cell.
                cell_address: Address of the cell to receive the formula, e.g. "D1".
                formula: Formula string beginning with '=', e.g. "=SUM(A1:A10)".
                output_filename: Optional bare filename for the saved workbook. If omitted,
                                 a temporary file is created.
        
            Returns:
                dict: {
                    "status": "success" | "error",
                    "message": str,
                    "output_filename": str   # bare name of the written file
                }
        
            Raises:
                FileNotFoundError: If the input workbook does not exist.
                IndexError: If sheet_index is out of range.
                ValueError: If the formula is malformed (does not start with '=').
                Exception: For any unexpected Aspose error.
        
            Example:
                result = await cells_set_cell_formula(
                    input_filename="report.xlsx",
                    sheet_index=0,
                    cell_address="D1",
                    formula="=AVERAGE(B2:B10)",
                    output_filename="report_with_formula.xlsx",
                )
            """
            # ----------------------------------------------------------------------
            # Resolve and validate input file
            # ----------------------------------------------------------------------
            from pathlib import Path
            from mcp_server.path_utils import get_safe_path, temp_output_path
            import logging
        
            logger = logging.getLogger(__name__)
        
            # sanitize input filename
            input_filename = Path(input_filename.strip().replace("\x00", "")).name
            resolved_input = get_safe_path(input_filename)
            if not Path(resolved_input).is_file():
                raise FileNotFoundError(f"File not found: {input_filename}")
        
            # ----------------------------------------------------------------------
            # Resolve output location
            # ----------------------------------------------------------------------
            if output_filename is not None:
                output_filename = Path(output_filename.strip().replace("\x00", "")).name
                resolved_output = get_safe_path(output_filename)
            else:
                # generate a temporary filename with .xlsx extension
                temp_path = temp_output_path("aspose_cells_result", ".xlsx")
                resolved_output = str(temp_path)  # Aspose expects a plain string
                output_filename = Path(resolved_output).name
        
            # ensure output directory exists
            Path(resolved_output).parent.mkdir(parents=True, exist_ok=True)
        
            # ----------------------------------------------------------------------
            # Validate formula format early
            # ----------------------------------------------------------------------
            if not formula.startswith("="):
                raise ValueError("Formula must start with '='")
        
            # ----------------------------------------------------------------------
            # Aspose.Cells processing
            # ----------------------------------------------------------------------
            try:
                import aspose.cells as ac
        
                # load workbook
                wb = ac.Workbook(str(resolved_input))
        
                # access worksheet
                try:
                    ws = wb.worksheets[sheet_index]
                except IndexError as exc:
                    raise IndexError(f"Worksheet index {sheet_index} is out of range") from exc
        
                # set formula
                ws.cells.get(cell_address).formula = formula
        
                # save workbook
                wb.save(str(resolved_output), ac.SaveFormat.XLSX)
        
                logger.info(
                    "Formula %s set in %s!%s and saved to %s",
                    formula,
                    sheet_index,
                    cell_address,
                    output_filename,
                )
                return {
                    "status": "success",
                    "message": f"Formula applied and workbook saved as {output_filename}",
                    "output_filename": output_filename,
                }
        
            except Exception as exc:  # catch Aspose and any other unexpected errors
                logger.exception("Failed to set cell formula")
                return {
                    "status": "error",
                    "message": str(exc),
                    "output_filename": output_filename,
                }

