        @mcp.tool()
        async def cells_rename_worksheet(
            input_filename: str,
            sheet_index: int,
            new_name: str,
            output_filename: str | None = None,
        ) -> dict:
            """Rename a worksheet in an Excel workbook.
        
            IMPORTANT:
            * All *_filename parameters accept ONLY the bare filename (e.g. 'scan.jpg') — no path, no directory, no drive letter, no slash.
            * The file MUST already exist in the server's ASPOSE_FILES_PATH folder before calling this tool.
            * Do NOT ask the user to upload a file — files are pre‑placed in the server folder by the user.
            * The output file is also written to the ASPOSE_FILES_PATH folder; the returned output_filename is the bare name only.
        
            Args:
                input_filename: bare filename of the workbook containing the worksheet to rename.
                sheet_index: zero‑based index of the worksheet to rename.
                new_name: new name for the worksheet.
                output_filename: optional bare filename for the saved workbook after renaming.
        
            Returns:
                dict: {"status": "success"|"error", "message": str, "output_filename": str}
        
            Raises:
                FileNotFoundError: if the input workbook does not exist.
                ValueError: if sheet_index is out of range or new_name conflicts with an existing sheet.
        
            Example:
                result = await cells_rename_worksheet(
                    input_filename="report.xlsx",
                    sheet_index=0,
                    new_name="Summary",
                    output_filename="report_renamed.xlsx",
                )
            """
            # ----------------------------------------------------------------------
            # Resolve and validate file inputs (must happen before any Aspose import)
            # ----------------------------------------------------------------------
            from pathlib import Path
            from mcp_server.path_utils import get_safe_path, temp_output_path
            import logging
        
            logger = logging.getLogger(__name__)
        
            # sanitize input filename
            input_filename = Path(input_filename.strip().replace("\x00", "")).name
            resolved_input = get_safe_path(input_filename)
            if not Path(resolved_input).is_file():
                raise FileNotFoundError(f"File not found: {input_filename}")
        
            # sanitize optional output filename
            if output_filename is not None:
                output_filename = Path(output_filename.strip().replace("\x00", "")).name
        
            # resolve output path (or create a temporary one)
            if output_filename:
                resolved_output = get_safe_path(output_filename)
            else:
                temp_path = temp_output_path("aspose_cells_result", ".xlsx")
                resolved_output = str(temp_path)  # Aspose expects a plain string
                output_filename = Path(resolved_output).name
        
            # ensure the output directory exists
            Path(resolved_output).parent.mkdir(parents=True, exist_ok=True)
        
            # ----------------------------------------------------------------------
            # Aspose.Cells operations
            # ----------------------------------------------------------------------
            import aspose.cells as ac
        
            try:
                # Load the workbook
                wb = ac.Workbook(str(resolved_input))
        
                # Validate sheet index
                if sheet_index < 0 or sheet_index >= len(wb.worksheets):
                    raise ValueError(
                        f"sheet_index {sheet_index} is out of range (0‑{len(wb.worksheets) - 1})"
                    )
        
                # Check for name conflict with other worksheets
                for i in range(len(wb.worksheets)):
                    ws = wb.worksheets[i]
                    if i != sheet_index and ws.name == new_name:
                        raise ValueError(f"A worksheet with name '{new_name}' already exists.")
        
                # Rename the target worksheet
                ws_to_rename = wb.worksheets[sheet_index]
                ws_to_rename.name = new_name
        
                # Save the modified workbook
                wb.save(str(resolved_output), ac.SaveFormat.XLSX)
        
                logger.info("Worksheet renamed and workbook saved to %s", resolved_output)
                return {
                    "status": "success",
                    "message": f"Worksheet at index {sheet_index} renamed to '{new_name}'.",
                    "output_filename": output_filename,
                }
        
            except Exception as exc:  # pragma: no cover
                logger.exception("Failed to rename worksheet")
                return {
                    "status": "error",
                    "message": str(exc),
                    "output_filename": output_filename if output_filename else "",
                }

