        @mcp.tool()
        async def cells_auto_fit(
            input_filename: str,
            sheet_index: int | None = None,
            output_filename: str | None = None,
        ) -> dict:
            """
            Auto‑fit columns (and rows) of a workbook worksheet(s) using Aspose.Cells.
        
            IMPORTANT:
            * All *_filename parameters accept ONLY the bare filename (e.g. 'report.xlsx') — no path,
              no directory, no drive letter, no slash.
            * The file MUST already exist in the server's ASPOSE_FILES_PATH folder before calling this tool.
            * Do NOT ask the user to upload a file — files are pre‑placed in the server folder by the user.
            * The output file is also written to the ASPOSE_FILES_PATH folder; the returned output_filename
              is the bare name only.
        
            Args:
                input_filename: Bare filename of the workbook to auto‑fit. Must exist in ASPOSE_FILES_PATH.
                sheet_index: Optional zero‑based index of the worksheet to process. If omitted, all worksheets
                             are auto‑fitted.
                output_filename: Optional bare filename for the saved workbook. If omitted, a temporary
                                 filename is generated.
        
            Returns:
                dict: {
                    "status": "success" | "error",
                    "message": str,
                    "output_filename": str   # bare name of the written file (or empty string on error)
                }
        
            Raises:
                FileNotFoundError: If the input file does not exist.
                IndexError: If sheet_index is provided but out of range.
                Exception: Any other error raised by Aspose.Cells.
        
            Example:
                result = await cells_auto_fit(
                    input_filename="sales_data.xlsx",
                    sheet_index=2,
                    output_filename="sales_fitted.xlsx"
                )
            """
            # ----------------------------------------------------------------------
            # Resolve and validate input file
            # ----------------------------------------------------------------------
            from pathlib import Path
            from mcp_server.path_utils import get_safe_path, temp_output_path
        
            # sanitize filename, keep only the name part
            input_filename = Path(input_filename.strip().replace('\x00', '')).name
            resolved_input = get_safe_path(input_filename)
            if not Path(resolved_input).is_file():
                raise FileNotFoundError(f"File not found: {input_filename}")
        
            # ----------------------------------------------------------------------
            # Resolve output file
            # ----------------------------------------------------------------------
            if output_filename is not None:
                output_filename = Path(output_filename.strip().replace('\x00', '')).name
                resolved_output = get_safe_path(output_filename)
            else:
                # generate a temporary filename with .xlsx extension
                temp_path = temp_output_path("aspose_cells_result", ".xlsx")
                resolved_output = str(temp_path)  # Aspose expects a plain str
                output_filename = Path(resolved_output).name
        
            # ensure output directory exists
            Path(resolved_output).parent.mkdir(parents=True, exist_ok=True)
        
            # ----------------------------------------------------------------------
            # Perform Aspose.Cells auto‑fit
            # ----------------------------------------------------------------------
            import logging
            logger = logging.getLogger(__name__)
        
            try:
                import aspose.cells as ac
        
                # load workbook
                wb = ac.Workbook(str(resolved_input))
        
                if sheet_index is None:
                    # process all worksheets
                    for ws in wb.worksheets:
                        ws.auto_fit_columns()
                        ws.auto_fit_rows()
                else:
                    # process a single worksheet, raise IndexError if out of range
                    try:
                        ws = wb.worksheets[sheet_index]
                    except Exception as exc:
                        raise IndexError(f"Sheet index {sheet_index} is out of range.") from exc
                    ws.auto_fit_columns()
                    ws.auto_fit_rows()
        
                # save the modified workbook
                wb.save(str(resolved_output), ac.SaveFormat.XLSX)
        
                logger.info(
                    "Auto‑fit completed for %s (sheet_index=%s); saved to %s",
                    input_filename,
                    sheet_index,
                    output_filename,
                )
                return {
                    "status": "success",
                    "message": "Workbook auto‑fit completed successfully.",
                    "output_filename": output_filename,
                }
        
            except Exception as exc:
                logger.exception("Error during cells_auto_fit: %s", exc)
                return {
                    "status": "error",
                    "message": str(exc),
                    "output_filename": "",
                }

        @mcp.tool()
        async def cells_merge_cells(
            input_filename: str,
            sheet_index: int,
            start_cell: str,
            row_count: int,
            col_count: int,
            output_filename: str | None = None,
        ) -> dict:
            """
            Merge a rectangular range of cells in a workbook worksheet.
        
            IMPORTANT: All *_filename parameters accept ONLY the bare filename (e.g. 'scan.jpg') —
            no path, no directory, no drive letter, no slash. The file MUST already exist in the
            server's ASPOSE_FILES_PATH folder. Do NOT ask the user to upload a file — files are
            pre‑placed in that folder. Output files are written to the same folder; returned
            output_filename is the bare name only.
        
            Args:
                input_filename: Bare filename of the workbook containing the cells to merge.
                sheet_index: Zero‑based index of the worksheet where the merge will occur.
                start_cell: Top‑left cell address of the merge range (e.g., "A1").
                row_count: Number of rows to include in the merge.
                col_count: Number of columns to include in the merge.
                output_filename: Optional bare filename for the saved workbook after merging.
                                 If omitted, a temporary file is created.
        
            Returns:
                dict: {
                    "status": "success" | "error",
                    "message": str,
                    "output_filename": str   # bare name of the written file (present only on success)
                }
        
            Raises:
                FileNotFoundError: If the input workbook does not exist.
                ValueError: If the start_cell format is invalid or merge dimensions are out of range.
                Exception: For any unexpected Aspose.Cells errors.
        
            Example:
                result = await cells_merge_cells(
                    input_filename="sales.xlsx",
                    sheet_index=0,
                    start_cell="B2",
                    row_count=2,
                    col_count=3,
                    output_filename="merged.xlsx",
                )
            """
            # ----------------------------------------------------------------------
            # Resolve and validate input file
            # ----------------------------------------------------------------------
            from pathlib import Path
            from mcp_server.path_utils import get_safe_path, temp_output_path
            import logging
        
            logger = logging.getLogger(__name__)
        
            # sanitize filename
            input_filename = Path(input_filename.strip().replace("\x00", "")).name
            resolved_input = get_safe_path(input_filename)
            if not Path(resolved_input).is_file():
                raise FileNotFoundError(f"File not found: {input_filename}")
        
            # ----------------------------------------------------------------------
            # Resolve output file
            # ----------------------------------------------------------------------
            if output_filename is not None:
                output_filename = Path(output_filename.strip().replace("\x00", "")).name
                resolved_output = get_safe_path(output_filename)
            else:
                # temporary file with .xlsx extension
                temp_path = temp_output_path("aspose_cells_result", ".xlsx")
                resolved_output = str(temp_path)  # Aspose expects a plain string
                output_filename = Path(resolved_output).name
        
            # ensure output directory exists
            Path(resolved_output).parent.mkdir(parents=True, exist_ok=True)
        
            # ----------------------------------------------------------------------
            # Helper: convert Excel column letters to zero‑based index
            # ----------------------------------------------------------------------
            def column_letter_to_index(col: str) -> int:
                """
                Convert an Excel column letter (e.g., "A", "Z", "AA") to a zero‑based column index.
        
                Args:
                    col: Column letters as a string. Case‑insensitive.
        
                Returns:
                    int: Zero‑based column index (0 for "A", 1 for "B", ...).
        
                Raises:
                    ValueError: If `col` contains characters outside A‑Z.
        
                Example:
                    >>> column_letter_to_index("C")
                    2
                    >>> column_letter_to_index("AA")
                    26
                """
                col = col.upper()
                idx = 0
                for ch in col:
                    if not ("A" <= ch <= "Z"):
                        raise ValueError(f"Invalid column letter in start_cell: {col}")
                    idx = idx * 26 + (ord(ch) - ord("A") + 1)
                return idx - 1  # zero‑based
        
            # ----------------------------------------------------------------------
            # Parse start_cell (e.g., "C5")
            # ----------------------------------------------------------------------
            try:
                import re
        
                match = re.fullmatch(r"([A-Za-z]+)(\d+)", start_cell.strip())
                if not match:
                    raise ValueError
                col_letters, row_number = match.groups()
                first_row = int(row_number) - 1  # zero‑based
                first_col = column_letter_to_index(col_letters)
            except Exception:
                raise ValueError(f"Invalid start_cell format: '{start_cell}'. Expected like 'A1'.")
        
            # ----------------------------------------------------------------------
            # Perform merge using Aspose.Cells
            # ----------------------------------------------------------------------
            try:
                import aspose.cells as ac
        
                # Load workbook
                wb = ac.Workbook(str(resolved_input))
                # Access worksheet
                ws = wb.worksheets[sheet_index]
                # Perform merge
                ws.cells.merge(first_row, first_col, row_count, col_count)
                # Save result
                wb.save(str(resolved_output), ac.SaveFormat.XLSX)
        
                logger.info(
                    "Merged cells in %s (sheet %d) starting at %s (%d rows x %d cols) -> %s",
                    input_filename,
                    sheet_index,
                    start_cell,
                    row_count,
                    col_count,
                    output_filename,
                )
                return {
                    "status": "success",
                    "message": f"Cells merged and workbook saved as {output_filename}.",
                    "output_filename": output_filename,
                }
            except Exception as exc:
                logger.exception("Aspose.Cells merge failed: %s", exc)
                return {"status": "error", "message": str(exc)}

